            </div>

            {/* School Filter */}
            <div className="flex-1 flex flex-col gap-1">
              <label className="text-[10px] font-bold text-slate-400 flex items-center gap-1">
                <School className="w-3 h-3" /> تصفية حسب اسم المدرسة
              </label>
              <select 
                value={selectedSchoolName}
                onChange={(e) => setSelectedSchoolName(e.target.value)}
                className="bg-white border border-slate-200 rounded-lg px-3 py-2 text-sm outline-none focus:ring-2 focus:ring-indigo-500"
              >
                <option value="">كل المدارس</option>
                {uniqueSchoolNames.map(name => <option key={name} value={name}>{name}</option>)}
              </select>
            </div>
          </div>

          {/* Results Area */}
          <div className="flex-1 overflow-y-auto p-6 bg-slate-50">
            <div className="max-w-5xl mx-auto">
              <div className="flex items-center justify-between mb-6">
                <h2 className="text-lg font-bold text-slate-800">
                  النتائج المتاحة ({filteredSchools.length})
                </h2>
                {filteredSchools.length === 0 && (
                   <span className="text-xs text-slate-400">يرجى تعديل خيارات البحث</span>
                )}
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                {filteredSchools.length > 0 ? (
                  filteredSchools.map((school) => (
                    <div 
                      key={school.id}
                      className="bg-white p-5 rounded-2xl border border-slate-200 hover:border-indigo-400 hover:shadow-lg transition-all cursor-pointer group flex flex-col gap-4 shadow-sm relative overflow-hidden"
                    >
                      <div className="absolute top-0 right-0 w-1 h-full bg-indigo-600 opacity-0 group-hover:opacity-100 transition-opacity"></div>

                      <div onClick={() => handleSelectSchool(school.name)} className="flex justify-between items-start">
                        <div className="flex-1">
                          <h3 className="text-lg font-bold text-slate-800 group-hover:text-indigo-600 transition-colors leading-snug">
                            {school.name}
                          </h3>
                        </div>
                        <span className="bg-indigo-50 text-indigo-600 text-[10px] md:text-xs px-3 py-1 rounded-full font-bold whitespace-nowrap mr-2">
                          {school.governorate}
                        </span>
                      </div>

                      <div onClick={() => handleSelectSchool(school.name)} className="flex-1">
                        <div className="text-[10px] font-bold text-slate-400 uppercase mb-2 flex items-center gap-1">
                          <Layers className="w-3 h-3" /> التخصصات المتوفرة:
                        </div>
                        <div className="flex flex-wrap gap-1.5">
                          {school.specialty.split('،').map((s, idx) => (
                            <span 
                              key={idx} 
                              className="bg-indigo-50/50 text-indigo-700 text-[11px] px-2.5 py-1 rounded-lg border border-indigo-100 font-medium"
                            >
                              {s.trim()}
                            </span>
                          ))}
                        </div>
                      </div>

                      <div className="flex flex-col gap-3 pt-3 border-t border-slate-50 mt-auto">
                        <div onClick={() => handleSelectSchool(school.name)} className="text-[13px] text-slate-500 flex items-start gap-2">
                          <MapPin className="w-4 h-4 text-slate-400 mt-0.5 shrink-0" />
                          <span>{school.city} - {school.address}</span>
                        </div>

                        <div className="flex items-center gap-2">
                          <button 
                            onClick={() => handleSelectSchool(school.name)}
                            className="flex-1 bg-indigo-600 text-white text-xs font-bold px-4 py-2.5 rounded-xl hover:bg-indigo-700 transition-colors shadow-sm shadow-indigo-100"
                          >
                            عرض التفاصيل والتقديم
                          </button>
                          {school.mapUrl && (
                            <a 
                              href={school.mapUrl} 
                              target="_blank" 
                              rel="noopener noreferrer"
                              className="flex items-center justify-center gap-2 text-xs font-bold text-slate-600 hover:text-indigo-600 border border-slate-200 px-4 py-2.5 rounded-xl bg-white hover:border-indigo-200 transition-all shrink-0"
                            >
                              <ExternalLink className="w-4 h-4" />
                            </a>
                          )}
                        </div>
                      </div>
                    </div>
                  ))
                ) : (
                  <div className="col-span-full text-center py-20 bg-white rounded-3xl border border-dashed border-slate-300">
                    <Bot className="w-16 h-16 text-slate-200 mx-auto mb-4" />
                    <p className="text-slate-500 font-semibold mb-1">عذراً، لا توجد نتائج مطابقة لهذه الفلاتر</p>
                    <button 
                      onClick={resetFilters}
                      className="text-indigo-600 text-sm font-bold hover:underline"
                    >
                      عرض جميع المدارس المتاحة
                    </button>
                  </div>
                )}
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect, useMemo } from 'react';
import { Send, Bot, User, Loader2, RefreshCcw, Info, School, MapPin, Search, X, ChevronLeft, ExternalLink, Filter, Layers, Map, CheckCircle2 } from 'lucide-react';
import { chatService } from './services/geminiService';
import { Message, SchoolData } from './types';
import { INITIAL_MESSAGE, CSV_DATA } from './constants';

const EGYPT_GOVERNORATES = [
  "القاهرة", "الجيزة", "الإسكندرية", "الدقهلية", "البحر الأحمر", "البحيرة", "الفيوم", "الغربية", 
  "الإسماعيلية", "المنوفية", "المنيا", "القليوبية", "الوادي الجديد", "السويس", "الشرقية", 
  "دمياط", "بورسعيد", "جنوب سيناء", "كفر الشيخ", "مطروح", "الأقصر", "قنا", "شمال سيناء", 
  "سوهاج", "بني سويف", "أسيوط", "أسوان"
];

const App: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([
    { role: 'model', text: INITIAL_MESSAGE, timestamp: new Date() }
  ]);
  const [inputText, setInputText] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [isSearchOpen, setIsSearchOpen] = useState(false);

  // Filters State
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedGov, setSelectedGov] = useState('');
  const [selectedSpec, setSelectedSpec] = useState('');
  const [selectedSchoolName, setSelectedSchoolName] = useState('');

  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Parse CSV Data into objects
  const schools = useMemo(() => {
    const lines = CSV_DATA.trim().split('\n');
    return lines.map(line => {
      const parts = line.match(/(".*?"|[^",\s]+)(?=\s*,|\s*$)/g);
      if (!parts) return null;
      const clean = (s: string) => s.replace(/^"|"$/g, '').trim();
      return {
        id: clean(parts[0]),
        name: clean(parts[1]),
        governorate: clean(parts[2]),
        city: clean(parts[3]),
        specialty: clean(parts[4]),
        address: clean(parts[7]),
        mapUrl: clean(parts[8]),
        eligibleGovernorates: clean(parts[9]),
        status: clean(parts[10])
      } as SchoolData;
    }).filter(Boolean) as SchoolData[];
  }, []);

  // Filter Options Extraction
  const uniqueSpecialties = useMemo(() => {
    const allSpecs = schools.flatMap(s => s.specialty.split('،').map(spec => spec.trim()));
    return Array.from(new Set(allSpecs)).sort();
  }, [schools]);

  const uniqueSchoolNames = useMemo(() => 
    Array.from(new Set(schools.map(s => s.name))).sort()
  , [schools]);

  // Apply all filters
  const filteredSchools = useMemo(() => {
    return schools.filter(s => {
      const matchesSearch = !searchQuery.trim() || 
        s.name.toLowerCase().includes(searchQuery.toLowerCase()) || 
        s.specialty.toLowerCase().includes(searchQuery.toLowerCase()) || 
        s.governorate.toLowerCase().includes(searchQuery.toLowerCase());

      const matchesGov = !selectedGov || s.governorate === selectedGov;
      const matchesSpec = !selectedSpec || s.specialty.includes(selectedSpec);
      const matchesSchoolName = !selectedSchoolName || s.name === selectedSchoolName;

      return matchesSearch && matchesGov && matchesSpec && matchesSchoolName;
    });
  }, [searchQuery, selectedGov, selectedSpec, selectedSchoolName, schools]);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSendMessage = async (text: string) => {
    if (!text.trim() || isLoading) return;

    const userMessage: Message = {
      role: 'user',
      text: text,
      timestamp: new Date()
    };

    setMessages(prev => [...prev, userMessage]);
    setInputText('');
    setIsLoading(true);

    try {
      const modelResponseText = await chatService.sendMessage(text);
      const modelMessage: Message = {
        role: 'model',
        text: modelResponseText,
        timestamp: new Date()
      };
      setMessages(prev => [...prev, modelMessage]);
    } catch (error) {
      setMessages(prev => [...prev, {
        role: 'model',
        text: "عذراً، حدث خطأ فني. يرجى المحاولة مرة أخرى لاحقاً.",
        timestamp: new Date()
      }]);
    } finally {
      setIsLoading(false);
    }
  };

  const handleSelectSchool = (schoolName: string) => {
    setIsSearchOpen(false);
    resetFilters();
    handleSendMessage(`أريد معلومات مفصلة عن ${schoolName}`);
  };

  const resetFilters = () => {
    setSearchQuery('');
    setSelectedGov('');
    setSelectedSpec('');
    setSelectedSchoolName('');
  };

  const renderMessageContent = (text: string) => {
    const urlRegex = /(https?:\/\/[^\s]+)/g;
    const parts = text.split(urlRegex);

    return parts.map((part, i) => {
      if (part.match(urlRegex)) {
        return (
          <a 
            key={i} 
            href={part} 
            target="_blank" 
            rel="noopener noreferrer"
            className="inline-flex items-center gap-2 bg-indigo-50 text-indigo-700 px-4 py-2 rounded-xl mt-2 border border-indigo-200 hover:bg-indigo-100 transition-colors font-bold shadow-sm"
          >
            <MapPin className="w-4 h-4" />
            مشاهدة الموقع على الخريطة
            <ExternalLink className="w-3 h-3" />
          </a>
        );
      }
      return <span key={i}>{part}</span>;
    });
  };

  return (
    <div className="flex flex-col h-screen max-h-screen bg-slate-100 overflow-hidden font-['Cairo']">
      {/* Header */}
      <header className="bg-white border-b border-slate-200 px-6 py-4 flex items-center justify-between shadow-sm sticky top-0 z-10">
        <div className="flex items-center gap-3">
          <div className="bg-indigo-600 p-2 rounded-xl shadow-lg shadow-indigo-100">
            <Bot className="w-6 h-6 text-white" />
          </div>
          <div>
            <h1 className="text-xl font-bold text-slate-800">ATS-ChatBot <span className="text-sm font-normal text-indigo-500 bg-indigo-50 px-2 py-0.5 rounded-full mr-2">v.0.1</span></h1>
            <p className="text-xs text-green-500 font-semibold flex items-center gap-1">
              <span className="w-2 h-2 bg-green-500 rounded-full animate-pulse"></span>
              مساعد مدارس التكنولوجيا التطبيقية
            </p>
          </div>
        </div>
        <div className="flex gap-2">
          <button 
            onClick={() => setIsSearchOpen(true)}
            className="p-2.5 bg-indigo-50 hover:bg-indigo-100 text-indigo-700 rounded-2xl transition-all flex items-center gap-2 font-bold shadow-sm border border-indigo-100"
            title="بحث وتصفية المدارس"
          >
            <Filter className="w-5 h-5" />
            <span className="hidden md:inline">نظام التصفية</span>
          </button>
          <button 
            onClick={() => window.location.reload()} 
            className="p-2 hover:bg-slate-100 rounded-full transition-colors text-slate-500"
            title="إعادة بدء المحادثة"
          >
            <RefreshCcw className="w-5 h-5" />
          </button>
        </div>
      </header>

      {/* Main Chat Area */}
      <main className="flex-1 overflow-y-auto p-4 md:p-6 space-y-6 scrollbar-hide">
        {messages.map((msg, index) => (
          <div 
            key={index} 
            className={`flex ${msg.role === 'user' ? 'justify-start' : 'justify-end'} animate-in fade-in slide-in-from-bottom-2 duration-300`}
          >
            <div className={`flex gap-3 max-w-[95%] md:max-w-[80%] ${msg.role === 'user' ? 'flex-row' : 'flex-row-reverse'}`}>
              <div className={`flex-shrink-0 w-10 h-10 rounded-full flex items-center justify-center shadow-md ${
                msg.role === 'user' ? 'bg-indigo-600 text-white' : 'bg-white border border-slate-200 text-indigo-600'
              }`}>
                {msg.role === 'user' ? <User className="w-5 h-5" /> : <Bot className="w-5 h-5" />}
              </div>
              <div className={`p-5 rounded-2xl shadow-sm text-[15px] md:text-base leading-relaxed ${
                msg.role === 'user' 
                  ? 'bg-indigo-600 text-white rounded-tr-none' 
                  : 'bg-white text-slate-700 border border-slate-200 rounded-tl-none shadow-sm'
              }`}>
                <div className="whitespace-pre-wrap">{renderMessageContent(msg.text)}</div>
                <div className={`text-[10px] mt-3 opacity-60 ${msg.role === 'user' ? 'text-right' : 'text-left'}`}>
                  {msg.timestamp.toLocaleTimeString('ar-EG', { hour: '2-digit', minute: '2-digit' })}
                </div>
              </div>
            </div>
          </div>
        ))}
        {isLoading && (
          <div className="flex justify-end animate-in fade-in slide-in-from-bottom-1 duration-300">
             <div className="flex flex-row-reverse gap-3 max-w-[70%]">
              <div className="flex-shrink-0 w-10 h-10 rounded-full bg-white border border-slate-200 flex items-center justify-center text-indigo-600 shadow-sm">
                <Bot className="w-5 h-5" />
              </div>
              <div className="bg-white p-4 rounded-2xl border border-slate-200 rounded-tl-none shadow-sm">
                <Loader2 className="w-5 h-5 animate-spin text-indigo-600" />
              </div>
            </div>
          </div>
        )}
        <div ref={messagesEndRef} />
      </main>

      {/* Input Area */}
      <footer className="bg-white border-t border-slate-200 p-4 md:p-6 shadow-[0_-4px_20px_rgba(0,0,0,0.03)]">
        <form 
          onSubmit={(e) => { e.preventDefault(); handleSendMessage(inputText); }} 
          className="max-w-4xl mx-auto flex gap-3"
        >
          <input
            type="text"
            value={inputText}
            onChange={(e) => setInputText(e.target.value)}
            placeholder="اسأل عن أي مدرسة، تخصص، أو شروط التقديم..."
            className="flex-1 bg-slate-50 border border-slate-200 rounded-2xl px-6 py-4 focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:bg-white transition-all text-sm md:text-base text-slate-800 placeholder:text-slate-400"
            disabled={isLoading}
          />
          <button
            type="submit"
            disabled={!inputText.trim() || isLoading}
            className="bg-indigo-600 text-white px-5 rounded-2xl shadow-lg shadow-indigo-100 hover:bg-indigo-700 disabled:opacity-50 disabled:shadow-none transition-all flex items-center justify-center"
          >
            {isLoading ? <Loader2 className="w-6 h-6 animate-spin" /> : <Send className="w-6 h-6" />}
          </button>
        </form>
        <p className="text-center text-[11px] text-slate-400 mt-4 uppercase tracking-wider font-bold">
          ATS-ChatBot v.0.1 • قاعدة بيانات المدارس الموثقة لعام 2024
        </p>
      </footer>

      {/* Advanced Search & Filtering Overlay */}
      {isSearchOpen && (
        <div className="fixed inset-0 z-50 flex flex-col bg-slate-50 animate-in fade-in slide-in-from-top duration-300">
          {/* Top Bar */}
          <div className="bg-white px-6 py-5 border-b shadow-sm flex items-center gap-4">
            <button 
              onClick={() => { setIsSearchOpen(false); resetFilters(); }} 
              className="p-2 hover:bg-slate-100 rounded-full transition-colors"
            >
              <ChevronLeft className="w-6 h-6 text-slate-600" />
            </button>
            <div className="flex-1">
              <h2 className="text-xl font-bold text-slate-800">نظام البحث والتصفية المتقدم</h2>
              <p className="text-xs text-slate-500">استخدم الخيارات أدناه للوصول السريع للمدارس</p>
            </div>
            <button 
              onClick={resetFilters}
              className="px-4 py-2 bg-slate-100 hover:bg-slate-200 text-slate-600 rounded-xl text-xs font-bold transition-colors flex items-center gap-2"
            >
              <RefreshCcw className="w-3.5 h-3.5" /> إعادة ضبط
            </button>
          </div>

          {/* Filtering Section */}
          <div className="bg-white px-6 pb-6 pt-2 border-b grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 items-end">
            {/* Quick Keyword */}
            <div className="flex flex-col gap-2">
              <label className="text-[11px] font-bold text-indigo-600 flex items-center gap-1.5 px-1">
                <Search className="w-3.5 h-3.5" /> بحث حر بالكلمات
              </label>
              <div className="relative">
                <input
                  type="text"
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  placeholder="اسم مدرسة، تخصص..."
                  className="w-full bg-slate-50 border border-slate-200 rounded-xl pl-4 pr-10 py-3 text-sm focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
                />
                <Search className="absolute right-3.5 top-1/2 -translate-y-1/2 w-4.5 h-4.5 text-slate-400" />
              </div>
            </div>

            {/* Gov Dropdown */}
            <div className="flex flex-col gap-2">
              <label className="text-[11px] font-bold text-indigo-600 flex items-center gap-1.5 px-1">
                <Map className="w-3.5 h-3.5" /> تصفية حسب المحافظة (27)
              </label>
              <select 
                value={selectedGov}
                onChange={(e) => setSelectedGov(e.target.value)}
                className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 text-sm outline-none focus:ring-2 focus:ring-indigo-500 appearance-none cursor-pointer"
              >
                <option value="">كل محافظات مصر</option>
                {EGYPT_GOVERNORATES.map(gov => <option key={gov} value={gov}>{gov}</option>)}
              </select>
            </div>

            {/* Specialty Dropdown */}
            <div className="flex flex-col gap-2">
              <label className="text-[11px] font-bold text-indigo-600 flex items-center gap-1.5 px-1">
                <Layers className="w-3.5 h-3.5" /> تصفية حسب التخصصات
              </label>
              <select 
                value={selectedSpec}
                onChange={(e) => setSelectedSpec(e.target.value)}
                className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 text-sm outline-none focus:ring-2 focus:ring-indigo-500 appearance-none cursor-pointer"
              >
                <option value="">جميع التخصصات المتاحة</option>
                {uniqueSpecialties.map(spec => <option key={spec} value={spec}>{spec}</option>)}
              </select>
            </div>

            {/* School Dropdown */}
            <div className="flex flex-col gap-2">
              <label className="text-[11px] font-bold text-indigo-600 flex items-center gap-1.5 px-1">
                <School className="w-3.5 h-3.5" /> اختر مدرسة محددة
              </label>
              <select 
                value={selectedSchoolName}
                onChange={(e) => setSelectedSchoolName(e.target.value)}
                className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 text-sm outline-none focus:ring-2 focus:ring-indigo-500 appearance-none cursor-pointer"
              >
                <option value="">قائمة جميع المدارس (117+)</option>
                {uniqueSchoolNames.map(name => <option key={name} value={name}>{name}</option>)}
              </select>
            </div>
          </div>

          {/* Results Area */}
          <div className="flex-1 overflow-y-auto p-6 scrollbar-hide">
            <div className="max-w-6xl mx-auto">
              <div className="flex items-center justify-between mb-8">
                <div className="flex items-center gap-3">
                  <div className="bg-indigo-600 text-white px-3 py-1 rounded-lg text-sm font-bold shadow-sm">
                    {filteredSchools.length}
                  </div>
                  <h3 className="text-lg font-bold text-slate-800">مدرسة مطابقة لخياراتك</h3>
                </div>
                {filteredSchools.length > 0 && (
                  <p className="text-xs text-slate-400 font-medium italic">انقر على المدرسة للحصول على تفاصيل التقديم عبر المحادثة</p>
                )}
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 pb-20">
                {filteredSchools.length > 0 ? (
                  filteredSchools.map((school) => (
                    <div 
                      key={school.id}
                      onClick={() => handleSelectSchool(school.name)}
                      className="group bg-white p-6 rounded-[2rem] border border-slate-200 hover:border-indigo-500 hover:shadow-2xl hover:shadow-indigo-100 transition-all cursor-pointer flex flex-col gap-5 relative overflow-hidden"
                    >
                      <div className="absolute top-0 right-0 w-16 h-16 bg-indigo-50 rounded-bl-[2rem] -mr-4 -mt-4 group-hover:bg-indigo-100 transition-colors flex items-center justify-center pt-3 pr-3">
                        <CheckCircle2 className="w-5 h-5 text-indigo-400 group-hover:text-indigo-600 transition-colors" />
                      </div>

                      <div className="flex-1">
                        <div className="flex flex-wrap gap-2 mb-3">
                          <span className="bg-indigo-600 text-white text-[10px] font-bold px-3 py-1 rounded-full uppercase tracking-tighter shadow-sm">
                            {school.governorate}
                          </span>
                          <span className="bg-slate-100 text-slate-500 text-[10px] font-bold px-3 py-1 rounded-full">
                            ID: {school.id}
                          </span>
                        </div>
                        <h3 className="text-lg font-bold text-slate-800 group-hover:text-indigo-600 transition-colors leading-snug mb-4">
                          {school.name}
                        </h3>

                        <div className="space-y-3">
                          <div className="text-[11px] font-bold text-slate-400 flex items-center gap-1.5 border-b border-slate-50 pb-2 mb-2">
                             <Layers className="w-3.5 h-3.5" /> التخصصات النوعية
                          </div>
                          <div className="flex flex-wrap gap-2">
                            {school.specialty.split('،').map((s, idx) => (
                              <span 
                                key={idx} 
                                className="bg-indigo-50/40 text-indigo-800 text-[11px] px-3 py-1.5 rounded-xl border border-indigo-100 font-bold group-hover:bg-indigo-600 group-hover:text-white group-hover:border-transparent transition-all"
                              >
                                {s.trim()}
                              </span>
                            ))}
                          </div>
                        </div>
                      </div>

                      <div className="pt-4 border-t border-slate-50 space-y-3">
                        <div className="text-[13px] text-slate-500 flex items-start gap-2.5 leading-relaxed">
                          <MapPin className="w-4.5 h-4.5 text-indigo-400 mt-0.5 shrink-0" />
                          <span>{school.city} • {school.address}</span>
                        </div>

                        <div className="flex items-center gap-2 mt-2">
                          <div className="flex-1 text-center bg-indigo-50 text-indigo-700 text-xs font-bold py-3 rounded-2xl group-hover:bg-indigo-600 group-hover:text-white transition-all shadow-sm">
                            استشارة الذكاء الاصطناعي
                          </div>
                          {school.mapUrl && (
                            <a 
                              href={school.mapUrl} 
                              target="_blank" 
                              rel="noopener noreferrer"
                              onClick={(e) => e.stopPropagation()}
                              className="w-12 h-12 flex items-center justify-center bg-slate-50 text-slate-400 hover:text-indigo-600 hover:bg-white border border-slate-100 hover:border-indigo-200 rounded-2xl transition-all shrink-0 shadow-sm"
                            >
                              <ExternalLink className="w-5 h-5" />
                            </a>
                          )}
                        </div>
                      </div>
                    </div>
                  ))
                ) : (
                  <div className="col-span-full text-center py-24 bg-white rounded-[3rem] border-2 border-dashed border-slate-200 shadow-inner">
                    <Bot className="w-20 h-20 text-slate-100 mx-auto mb-6" />
                    <h4 className="text-xl font-bold text-slate-800 mb-2">لا توجد مدارس مطابقة للبحث</h4>
                    <p className="text-slate-400 max-w-sm mx-auto mb-8 text-sm">حاول تغيير خيارات التصفية أو مسح جميع الفلاتر لاستعراض القائمة الكاملة.</p>
                    <button 
                      onClick={resetFilters}
                      className="bg-indigo-600 text-white px-8 py-3 rounded-2xl font-bold hover:bg-indigo-700 transition-all shadow-lg shadow-indigo-100"
                    >
                      عرض جميع المدارس (117)
                    </button>
                  </div>
                )}
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect, useMemo } from 'react';
import { Send, Bot, User, Loader2, RefreshCcw, Info, School, MapPin, Search, X, ChevronLeft, ExternalLink, Filter, Layers, Map, CheckCircle2, Building2 } from 'lucide-react';
import { chatService } from './services/geminiService';
import { Message, SchoolData } from './types';
import { INITIAL_MESSAGE, CSV_DATA } from './constants';

const EGYPT_GOVERNORATES = [
  "القاهرة", "الجيزة", "الإسكندرية", "الدقهلية", "البحر الأحمر", "البحيرة", "الفيوم", "الغربية", 
  "الإسماعيلية", "المنوفية", "المنيا", "القليوبية", "الوادي الجديد", "السويس", "الشرقية", 
  "دمياط", "بورسعيد", "جنوب سيناء", "كفر الشيخ", "مطروح", "الأقصر", "قنا", "شمال سيناء", 
  "سوهاج", "بني سويف", "أسيوط", "أسوان"
];

const App: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([
    { role: 'model', text: INITIAL_MESSAGE, timestamp: new Date() }
  ]);
  const [inputText, setInputText] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [isSearchOpen, setIsSearchOpen] = useState(false);

  // Filters State
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedGov, setSelectedGov] = useState('');
  const [selectedSpec, setSelectedSpec] = useState('');
  const [selectedSchoolName, setSelectedSchoolName] = useState('');

  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Parse CSV Data into objects
  const schools = useMemo(() => {
    const lines = CSV_DATA.trim().split('\n');
    return lines.map(line => {
      const parts = line.match(/(".*?"|[^",\s]+)(?=\s*,|\s*$)/g);
      if (!parts) return null;
      const clean = (s: string) => s.replace(/^"|"$/g, '').trim();
      return {
        id: clean(parts[0]),
        name: clean(parts[1]),
        governorate: clean(parts[2]),
        city: clean(parts[3]),
        specialty: clean(parts[4]),
        address: clean(parts[7]),
        mapUrl: clean(parts[8]),
        eligibleGovernorates: clean(parts[9]),
        status: clean(parts[10])
      } as SchoolData;
    }).filter(Boolean) as SchoolData[];
  }, []);

  // Filter Options Extraction from actual data
  const uniqueSpecialties = useMemo(() => {
    const allSpecs = schools.flatMap(s => s.specialty.split(/،|,/).map(spec => spec.trim()));
    return Array.from(new Set(allSpecs)).filter(Boolean).sort();
  }, [schools]);

  const uniqueSchoolNames = useMemo(() => 
    Array.from(new Set(schools.map(s => s.name))).filter(Boolean).sort()
  , [schools]);

  // Apply all filters
  const filteredSchools = useMemo(() => {
    return schools.filter(s => {
      const matchesSearch = !searchQuery.trim() || 
        s.name.toLowerCase().includes(searchQuery.toLowerCase()) || 
        s.specialty.toLowerCase().includes(searchQuery.toLowerCase()) || 
        s.governorate.toLowerCase().includes(searchQuery.toLowerCase());

      const matchesGov = !selectedGov || s.governorate === selectedGov;
      const matchesSpec = !selectedSpec || s.specialty.includes(selectedSpec);
      const matchesSchoolName = !selectedSchoolName || s.name === selectedSchoolName;

      return matchesSearch && matchesGov && matchesSpec && matchesSchoolName;
    });
  }, [searchQuery, selectedGov, selectedSpec, selectedSchoolName, schools]);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSendMessage = async (text: string) => {
    if (!text.trim() || isLoading) return;

    const userMessage: Message = {
      role: 'user',
      text: text,
      timestamp: new Date()
    };

    setMessages(prev => [...prev, userMessage]);
    setInputText('');
    setIsLoading(true);

    try {
      const modelResponseText = await chatService.sendMessage(text);
      const modelMessage: Message = {
        role: 'model',
        text: modelResponseText,
        timestamp: new Date()
      };
      setMessages(prev => [...prev, modelMessage]);
    } catch (error) {
      setMessages(prev => [...prev, {
        role: 'model',
        text: "عذراً، حدث خطأ فني أثناء معالجة طلبك. يرجى المحاولة مرة أخرى.",
        timestamp: new Date()
      }]);
    } finally {
      setIsLoading(false);
    }
  };

  const handleSelectSchool = (schoolName: string) => {
    setIsSearchOpen(false);
    resetFilters();
    handleSendMessage(`أريد معلومات كاملة وموثقة عن ${schoolName}`);
  };

  const resetFilters = () => {
    setSearchQuery('');
    setSelectedGov('');
    setSelectedSpec('');
    setSelectedSchoolName('');
  };

  const renderMessageContent = (text: string) => {
    const urlRegex = /(https?:\/\/[^\s]+)/g;
    const parts = text.split(urlRegex);

    return parts.map((part, i) => {
      if (part.match(urlRegex)) {
        return (
          <a 
            key={i} 
            href={part} 
            target="_blank" 
            rel="noopener noreferrer"
            className="inline-flex items-center gap-2 bg-indigo-50 text-indigo-700 px-4 py-2 rounded-xl mt-3 border border-indigo-200 hover:bg-indigo-100 transition-all font-bold shadow-sm"
          >
            <MapPin className="w-4 h-4" />
            تحديد الموقع (Google Maps)
            <ExternalLink className="w-3 h-3" />
          </a>
        );
      }
      return <span key={i}>{part}</span>;
    });
  };

  return (
    <div className="flex flex-col h-screen max-h-screen bg-slate-50 overflow-hidden font-['Cairo'] text-slate-900">
      {/* Header */}
      <header className="bg-white border-b border-slate-200 px-6 py-4 flex items-center justify-between shadow-sm sticky top-0 z-10">
        <div className="flex items-center gap-3">
          <div className="bg-indigo-600 p-2.5 rounded-2xl shadow-lg shadow-indigo-100">
            <Bot className="w-6 h-6 text-white" />
          </div>
          <div>
            <h1 className="text-xl font-bold text-slate-800 tracking-tight">ATS-ChatBot <span className="text-xs font-bold text-indigo-600 bg-indigo-50 px-2 py-0.5 rounded-lg mr-1 border border-indigo-100">v.0.1</span></h1>
            <p className="text-[10px] text-green-600 font-bold flex items-center gap-1 mt-0.5">
              <span className="w-1.5 h-1.5 bg-green-500 rounded-full animate-pulse"></span>
              المساعد الذكي لمدارس التكنولوجيا التطبيقية
            </p>
          </div>
        </div>
        <div className="flex gap-2">
          <button 
            onClick={() => setIsSearchOpen(true)}
            className="p-2.5 bg-white hover:bg-indigo-50 text-indigo-600 rounded-xl transition-all flex items-center gap-2 font-bold shadow-sm border border-slate-200 hover:border-indigo-200"
          >
            <Filter className="w-5 h-5" />
            <span className="hidden sm:inline text-sm">تصفية وبحث</span>
          </button>
          <button 
            onClick={() => setMessages([{ role: 'model', text: INITIAL_MESSAGE, timestamp: new Date() }])} 
            className="p-2.5 hover:bg-slate-100 rounded-xl transition-colors text-slate-400 border border-transparent"
            title="إعادة بدء"
          >
            <RefreshCcw className="w-5 h-5" />
          </button>
        </div>
      </header>

      {/* Main Chat Area */}
      <main className="flex-1 overflow-y-auto p-4 md:p-8 space-y-8 scrollbar-hide">
        {messages.map((msg, index) => (
          <div 
            key={index} 
            className={`flex ${msg.role === 'user' ? 'justify-start' : 'justify-end'} animate-in fade-in slide-in-from-bottom-3 duration-500`}
          >
            <div className={`flex gap-4 max-w-[95%] sm:max-w-[85%] md:max-w-[75%] ${msg.role === 'user' ? 'flex-row' : 'flex-row-reverse'}`}>
              <div className={`flex-shrink-0 w-11 h-11 rounded-2xl flex items-center justify-center shadow-lg transition-transform hover:scale-105 ${
                msg.role === 'user' ? 'bg-indigo-600 text-white' : 'bg-white border border-slate-200 text-indigo-600'
              }`}>
                {msg.role === 'user' ? <User className="w-6 h-6" /> : <Bot className="w-6 h-6" />}
              </div>
              <div className={`p-5 rounded-3xl shadow-md text-base leading-relaxed ${
                msg.role === 'user' 
                  ? 'bg-indigo-600 text-white rounded-tr-none' 
                  : 'bg-white text-slate-700 border border-slate-200 rounded-tl-none'
              }`}>
                <div className="whitespace-pre-wrap">{renderMessageContent(msg.text)}</div>
                <div className={`text-[10px] mt-4 font-bold uppercase tracking-widest ${msg.role === 'user' ? 'text-indigo-200 text-right' : 'text-slate-400 text-left'}`}>
                  {msg.timestamp.toLocaleTimeString('ar-EG', { hour: '2-digit', minute: '2-digit' })}
                </div>
              </div>
            </div>
          </div>
        ))}
        {isLoading && (
          <div className="flex justify-end animate-in fade-in slide-in-from-bottom-2">
             <div className="flex flex-row-reverse gap-4 max-w-[70%]">
              <div className="flex-shrink-0 w-11 h-11 rounded-2xl bg-white border border-slate-200 flex items-center justify-center text-indigo-600 shadow-sm">
                <Bot className="w-6 h-6 animate-bounce" />
              </div>
              <div className="bg-white p-5 rounded-3xl border border-slate-200 rounded-tl-none shadow-sm flex items-center">
                <Loader2 className="w-5 h-5 animate-spin text-indigo-600 mr-2" />
                <span className="text-sm text-slate-400 font-bold">جاري البحث في قاعدة البيانات...</span>
              </div>
            </div>
          </div>
        )}
        <div ref={messagesEndRef} />
      </main>

      {/* Footer / Input */}
      <footer className="bg-white border-t border-slate-200 p-4 md:p-8">
        <form 
          onSubmit={(e) => { e.preventDefault(); handleSendMessage(inputText); }} 
          className="max-w-4xl mx-auto flex gap-4"
        >
          <div className="flex-1 relative group">
            <input
              type="text"
              value={inputText}
              onChange={(e) => setInputText(e.target.value)}
              placeholder="اكتب اسم مدرسة، تخصص، أو استفسار عن التقديم..."
              className="w-full bg-slate-50 border border-slate-200 rounded-2xl px-6 py-4 focus:outline-none focus:ring-4 focus:ring-indigo-500/10 focus:bg-white focus:border-indigo-500 transition-all text-base text-slate-800 placeholder:text-slate-400"
              disabled={isLoading}
            />
            <div className="absolute left-4 top-1/2 -translate-y-1/2 flex items-center gap-2 pointer-events-none opacity-0 group-focus-within:opacity-100 transition-opacity">
              <span className="text-[10px] font-bold text-slate-300 bg-slate-100 px-2 py-1 rounded-lg">ENTER للإرسال</span>
            </div>
          </div>
          <button
            type="submit"
            disabled={!inputText.trim() || isLoading}
            className="bg-indigo-600 text-white px-8 rounded-2xl shadow-xl shadow-indigo-100 hover:bg-indigo-700 active:scale-95 disabled:opacity-50 disabled:active:scale-100 transition-all flex items-center justify-center"
          >
            {isLoading ? <Loader2 className="w-6 h-6 animate-spin" /> : <Send className="w-6 h-6" />}
          </button>
        </form>
        <div className="flex flex-wrap justify-center gap-4 mt-6">
          <p className="text-[11px] text-slate-400 font-bold uppercase tracking-wider flex items-center gap-2">
            <CheckCircle2 className="w-3.5 h-3.5 text-indigo-400" /> معلومات موثقة من وزارة التربية والتعليم
          </p>
          <p className="text-[11px] text-slate-400 font-bold uppercase tracking-wider flex items-center gap-2">
            <Building2 className="w-3.5 h-3.5 text-indigo-400" /> تغطي كافة محافظات الجمهورية
          </p>
        </div>
      </footer>

      {/* Advanced Search Overlay */}
      {isSearchOpen && (
        <div className="fixed inset-0 z-50 flex flex-col bg-slate-50 animate-in fade-in slide-in-from-top duration-300">
          {/* Search Header */}
          <div className="bg-white px-6 py-5 border-b shadow-sm flex items-center gap-4">
            <button onClick={() => { setIsSearchOpen(false); resetFilters(); }} className="p-3 hover:bg-slate-100 rounded-2xl transition-colors">
              <ChevronLeft className="w-6 h-6 text-slate-600" />
            </button>
            <div className="flex-1">
              <h2 className="text-xl font-bold text-slate-800 flex items-center gap-2">
                <Search className="w-5 h-5 text-indigo-600" /> استكشاف المدارس والتخصصات
              </h2>
            </div>
            <button 
              onClick={resetFilters}
              className="px-4 py-2 bg-slate-100 hover:bg-red-50 text-slate-600 hover:text-red-600 rounded-xl text-xs font-bold transition-all flex items-center gap-2"
            >
              <RefreshCcw className="w-3.5 h-3.5" /> تصفير
            </button>
          </div>

          {/* Filtering Section */}
          <div className="bg-white px-6 pb-8 pt-2 border-b grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6 items-end sticky top-0 z-20">
            {/* Quick Keyword */}
            <div className="flex flex-col gap-2">
              <label className="text-[11px] font-bold text-indigo-600 flex items-center gap-1.5 px-1 uppercase tracking-wide">
                <Search className="w-3 h-3" /> البحث بكلمة دالة
              </label>
              <div className="relative">
                <input
                  type="text"
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  placeholder="اسم المدرسة أو تخصص..."
                  className="w-full bg-slate-50 border border-slate-200 rounded-xl pl-4 pr-11 py-3.5 text-sm focus:ring-4 focus:ring-indigo-500/10 outline-none transition-all focus:border-indigo-500"
                />
                <Search className="absolute right-4 top-1/2 -translate-y-1/2 w-4.5 h-4.5 text-slate-400" />
              </div>
            </div>

            {/* Gov Dropdown */}
            <div className="flex flex-col gap-2">
              <label className="text-[11px] font-bold text-indigo-600 flex items-center gap-1.5 px-1 uppercase tracking-wide">
                <Map className="w-3 h-3" /> المحافظة (27 محافظة)
              </label>
              <select 
                value={selectedGov}
                onChange={(e) => setSelectedGov(e.target.value)}
                className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3.5 text-sm outline-none focus:ring-4 focus:ring-indigo-500/10 transition-all cursor-pointer appearance-none focus:border-indigo-500"
              >
                <option value="">كل محافظات الجمهورية</option>
                {EGYPT_GOVERNORATES.map(gov => <option key={gov} value={gov}>{gov}</option>)}
              </select>
            </div>

            {/* Specialty Dropdown */}
            <div className="flex flex-col gap-2">
              <label className="text-[11px] font-bold text-indigo-600 flex items-center gap-1.5 px-1 uppercase tracking-wide">
                <Layers className="w-3 h-3" /> التخصص الدراسي
              </label>
              <select 
                value={selectedSpec}
                onChange={(e) => setSelectedSpec(e.target.value)}
                className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3.5 text-sm outline-none focus:ring-4 focus:ring-indigo-500/10 transition-all cursor-pointer appearance-none focus:border-indigo-500"
              >
                <option value="">عرض جميع التخصصات</option>
                {uniqueSpecialties.map(spec => <option key={spec} value={spec}>{spec}</option>)}
              </select>
            </div>

            {/* School Dropdown */}
            <div className="flex flex-col gap-2">
              <label className="text-[11px] font-bold text-indigo-600 flex items-center gap-1.5 px-1 uppercase tracking-wide">
                <School className="w-3 h-3" /> المدرسة (117 مدرسة)
              </label>
              <select 
                value={selectedSchoolName}
                onChange={(e) => setSelectedSchoolName(e.target.value)}
                className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3.5 text-sm outline-none focus:ring-4 focus:ring-indigo-500/10 transition-all cursor-pointer appearance-none focus:border-indigo-500"
              >
                <option value="">كل المدارس الموثقة</option>
                {uniqueSchoolNames.map(name => <option key={name} value={name}>{name}</option>)}
              </select>
            </div>
          </div>

          {/* Results Area */}
          <div className="flex-1 overflow-y-auto p-6 md:p-10 scrollbar-hide">
            <div className="max-w-7xl mx-auto">
              <div className="flex items-end justify-between mb-10 pb-4 border-b border-slate-200">
                <div className="flex items-center gap-4">
                  <div className="bg-indigo-600 text-white text-xl font-black px-5 py-2 rounded-2xl shadow-lg shadow-indigo-100">
                    {filteredSchools.length}
                  </div>
                  <div>
                    <h3 className="text-2xl font-black text-slate-800 tracking-tight">مدرسة متاحة حالياً</h3>
                    <p className="text-sm text-slate-400 font-bold mt-1">بناءً على تفضيلات البحث الحالية</p>
                  </div>
                </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-8 pb-32">
                {filteredSchools.length > 0 ? (
                  filteredSchools.map((school) => (
                    <div 
                      key={school.id}
                      onClick={() => handleSelectSchool(school.name)}
                      className="group bg-white p-7 rounded-[2.5rem] border border-slate-200 hover:border-indigo-500 hover:shadow-2xl hover:shadow-indigo-500/10 transition-all cursor-pointer flex flex-col gap-6 relative overflow-hidden"
                    >
                      <div className="flex justify-between items-start">
                        <div className="flex flex-wrap gap-2">
                          <span className="bg-indigo-600 text-white text-[10px] font-black px-4 py-1.5 rounded-full uppercase tracking-widest shadow-md">
                            {school.governorate}
                          </span>
                          {school.status.includes('داخل مصنع') && (
                            <span className="bg-amber-100 text-amber-700 text-[10px] font-black px-4 py-1.5 rounded-full uppercase tracking-widest border border-amber-200">
                              داخل مصنع
                            </span>
                          )}
                        </div>
                        <div className="bg-slate-50 text-slate-400 p-2 rounded-xl border border-slate-100 group-hover:bg-indigo-50 group-hover:text-indigo-600 transition-colors">
                          <CheckCircle2 className="w-5 h-5" />
                        </div>
                      </div>

                      <div className="flex-1">
                        <h3 className="text-xl font-black text-slate-800 group-hover:text-indigo-600 transition-colors leading-tight mb-6">
                          {school.name}
