                        <div className="flex items-center gap-3 mt-4">
                          <div className="flex-1 text-center bg-slate-900 text-white text-[11px] font-black py-4 rounded-2xl group-hover:bg-indigo-600 transition-all shadow-lg uppercase tracking-widest">
