                    ) : (
                      <button onClick={resetFilters} className="bg-indigo-600 text-white px-10 py-4 rounded-[2rem] font-black hover:bg-indigo-700 transition-all shadow-2xl shadow-indigo-200"> عرض كافة المدارس (117 مدرسة) </button>
                    )}
                  </div>
                )}
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

