                <div className={`text-[10px] mt-4 font-bold ${msg.role === 'user' ? 'text-indigo-200 text-right' : 'text-slate-400 text-left'}`}>
                  {msg.timestamp.toLocaleTimeString('ar-EG', { hour: '2-digit', minute: '2-digit' })}
