      setIsLoading(false);
    }
  };

  const handleSelectSchool = (schoolName: string) => {
    setIsSearchOpen(false);
    resetFilters();
    handleSendMessage(`أريد معلومات كاملة وموثقة عن مدرسة ${schoolName}`);
