        </div>
        <div className="flex gap-2">
          <button onClick={() => setIsSearchOpen(true)} className="p-2.5 bg-white hover:bg-indigo-50 text-indigo-600 rounded-xl transition-all flex items-center gap-2 font-bold shadow-sm border border-slate-200">
            <Filter className="w-5 h-5" /> <span className="hidden sm:inline text-sm">البحث والمفضلة</span>
          </button>
          <button onClick={handleClearCache} className="p-2.5 hover:bg-red-50 rounded-xl transition-colors text-slate-400 hover:text-red-500" title="تفريغ الكاش والبدء من جديد">
