                      </div>
                      <div className="flex-1">
                        <h3 className="text-xl font-black text-slate-800 group-hover:text-indigo-600 transition-colors leading-tight mb-6"> {school.name} </h3>
                        <div className="space-y-4">
                          <div className="text-[10px] font-black text-slate-400 flex items-center gap-2 uppercase tracking-[0.1em] border-b border-slate-50 pb-2"> <Layers className="w-4 h-4 text-indigo-400" /> التخصصات الدراسية </div>
                          <div className="flex flex-wrap gap-2">
                            {school.specialty && (school.specialty.split(/،|,/)).map((s, idx) => (
                              <span key={idx} className="bg-indigo-50/50 text-indigo-800 text-[11px] px-3 py-1.5 rounded-xl border border-indigo-100/50 font-bold transition-all group-hover:bg-indigo-600 group-hover:text-white group-hover:border-transparent"> {s.trim()} </span>
                            ))}
                          </div>
                        </div>
                      </div>
                      <div className="pt-6 border-t border-slate-50 space-y-4 mt-auto">
                        <div className="flex items-start gap-3">
                          <MapPin className="w-5 h-5 text-indigo-400 shrink-0 mt-0.5" />
                          <div className="text-sm text-slate-500 font-bold leading-relaxed"> {school.city} • {school.address} </div>
                        </div>
                        <div className="flex items-center gap-3">
                          <div className="flex-1 text-center bg-indigo-600 text-white text-xs font-bold py-4 rounded-2xl group-hover:bg-indigo-700 transition-all shadow-md"> عرض التفاصيل </div>
                          {school.mapUrl && (
                            <a href={school.mapUrl} target="_blank" rel="noopener noreferrer" onClick={(e) => e.stopPropagation()} className="w-14 h-14 flex items-center justify-center bg-white text-slate-400 hover:text-indigo-600 border border-slate-200 hover:border-indigo-200 rounded-2xl transition-all shadow-sm"> <ExternalLink className="w-6 h-6" /> </a>
                          )}
                        </div>
                      </div>
                    </div>
                  ))
                ) : (
                  <div className="col-span-full text-center py-32 bg-white rounded-[4rem] border-2 border-dashed border-slate-200">
                    <Bot className="w-20 h-20 text-slate-100 mx-auto mb-8 animate-pulse" />
                    <h4 className="text-2xl font-black text-slate-800 mb-3"> لم نجد نتائج مطابقة لبيانات v3 </h4>
                    <p className="text-slate-400 max-w-sm mx-auto mb-10 text-base font-bold"> حاول تغيير معايير البحث أو المحافظة المختارة. </p>
                    <button onClick={resetFilters} className="bg-indigo-600 text-white px-10 py-4 rounded-[2rem] font-black hover:bg-indigo-700 shadow-xl"> إعادة عرض الكل </button>
                  </div>
                )}
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

