  const renderMessageContent = (text: string) => {
    if (!text) return null;
    const urlRegex = /(https?:\/\/[^\s]+)/g;
    const parts = text.split(urlRegex);
    return parts.map((part, i) => {
      if (part.match(urlRegex)) {
        return (
          <a key={i} href={part} target="_blank" rel="noopener noreferrer" className="inline-flex items-center gap-2 bg-indigo-50 text-indigo-700 px-4 py-2 rounded-xl mt-3 border border-indigo-200 hover:bg-indigo-100 transition-all font-bold shadow-sm">
            <MapPin className="w-4 h-4" /> عرض الموقع <ExternalLink className="w-3 h-3" />
          </a>
        );
      }
      return <span key={i}>{part}</span>;
    });
  };

  return (
    <div className="flex flex-col h-screen max-h-screen bg-slate-50 overflow-hidden font-['Cairo'] text-slate-900">
      <header className="bg-white border-b border-slate-200 px-6 py-4 flex items-center justify-between shadow-sm sticky top-0 z-10">
        <div className="flex items-center gap-3">
          <div className="bg-indigo-600 p-2.5 rounded-2xl shadow-lg">
            <Bot className="w-6 h-6 text-white" />
          </div>
          <div>
            <h1 className="text-xl font-bold text-slate-800 tracking-tight">ATS-ChatBot <span className="text-xs font-bold text-indigo-600 bg-indigo-50 px-2 py-0.5 rounded-lg mr-1 border border-indigo-100">v.0.1</span></h1>
            <p className="text-[10px] text-green-600 font-bold flex items-center gap-1 mt-0.5">
              <span className="w-1.5 h-1.5 bg-green-500 rounded-full animate-pulse"></span> قاعدة بيانات v3 موثقة
            </p>
          </div>
        </div>
        <div className="flex gap-2">
          <button onClick={() => setIsSearchOpen(true)} className="p-2.5 bg-white hover:bg-indigo-50 text-indigo-600 rounded-xl transition-all flex items-center gap-2 font-bold shadow-sm border border-slate-200">
            <Filter className="w-5 h-5" /> <span className="hidden sm:inline text-sm">تصفح المدارس</span>
          </button>
          <button onClick={handleClearCache} className="p-2.5 hover:bg-red-50 rounded-xl transition-colors text-slate-400 hover:text-red-500" title="تفريغ الكاش والبدء من جديد">
            <RefreshCcw className="w-5 h-5" />
          </button>
        </div>
      </header>

      <main className="flex-1 overflow-y-auto p-4 md:p-8 space-y-8 scrollbar-hide">
        {messages.map((msg, index) => (
          <div key={index} className={`flex ${msg.role === 'user' ? 'justify-start' : 'justify-end'} animate-in fade-in slide-in-from-bottom-3 duration-500`}>
            <div className={`flex gap-4 max-w-[95%] sm:max-w-[85%] md:max-w-[75%] ${msg.role === 'user' ? 'flex-row' : 'flex-row-reverse'}`}>
